import { initializeApp, getApps } from "firebase/app";
    import { getFirestore } from "firebase/firestore";
import { getAuth } from "firebase/auth";

const firebaseConfig = {
  apiKey: import.meta.env.VITE_FIREBASE_API_KEY,
  authDomain: import.meta.env.VITE_FIREBASE_AUTH_DOMAIN,
  projectId: import.meta.env.VITE_FIREBASE_PROJECT_ID,
  storageBucket: import.meta.env.VITE_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: import.meta.env.VITE_FIREBASE_MESSAGING_SENDER_ID,
  appId: import.meta.env.VITE_FIREBASE_APP_ID
};

// Enable Firestore debug logging to diagnose "offline" errors
// setLogLevel('debug');

// Validate required config
const requiredFields = ['apiKey', 'authDomain', 'projectId'];
const missingFields = requiredFields.filter(field => !firebaseConfig[field]);

if (missingFields.length > 0) {
  console.error('Firebase configuration is incomplete. Missing fields:', missingFields);
  console.error('Available env vars:', Object.keys(import.meta.env).filter(key => key.startsWith('VITE_FIREBASE_')));
  throw new Error(`Firebase configuration incomplete. Missing: ${missingFields.join(', ')}`);
}

// Singleton pattern pour éviter les doubles initialisations (Source: Firebase SDK Best Practices)
const app = getApps().length === 0 ? initializeApp(firebaseConfig) : getApps()[0];

export const db = getFirestore(app);
export const auth = getAuth(app);
export default app;

import { useState, useEffect } from 'react';
import { auth, db } from '../firebase/config'; // Importez l'instance déjà configurée
import { 
  onAuthStateChanged, 
  signInAnonymously, 
  signInWithEmailAndPassword, 
  signOut,
  createUserWithEmailAndPassword
} from 'firebase/auth';
import { doc, getDoc, setDoc, updateDoc, query, where, collection, getDocs } from 'firebase/firestore';

export function useAuth() {
  const [user, setUser] = useState(null);
  const [userData, setUserData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Écouteur de session
    const unsubscribe = onAuthStateChanged(auth, async (currentUser) => {
      console.log("🔥 État Auth changé :", currentUser ? "Connecté " + currentUser.uid : "Déconnecté");
      setUser(currentUser);
      if (currentUser) {
        const userDocRef = doc(db, 'users', currentUser.uid);
        const userDoc = await getDoc(userDocRef);
        if (userDoc.exists()) {
          setUserData(userDoc.data());
        } else {
          const defaultData = { role: 'regular', email: currentUser.email };
          await setDoc(userDocRef, defaultData);
          setUserData(defaultData);
        }
      } else {
        setUserData(null);
      }
      setLoading(false);
    });
    return () => unsubscribe();
  }, []);

  useEffect(() => {
    const initializeAdmin = async () => {
      // Only attempt to initialize if we haven't checked/initialized in this session
      // to avoid constant console noise and Firebase Auth requests.
      if (window._adminInitialized) return;
      window._adminInitialized = true;

      try {
        const adminEmail = 'admin@example.com';
        const userCredential = await createUserWithEmailAndPassword(auth, adminEmail, '123456');
        const userDoc = doc(db, 'users', userCredential.user.uid);
        await setDoc(userDoc, { role: 'admin', email: adminEmail });
        await signOut(auth);
      } catch (error) {
        // 'auth/email-already-in-use' is the standard SDK error code
        if (error.code === 'auth/email-already-in-use' || error.message?.includes('EMAIL_EXISTS')) {
          // User exists, ensure their role is admin in Firestore
          try {
            const q = query(collection(db, 'users'), where('email', '==', 'admin@example.com'));
            const querySnapshot = await getDocs(q);
            if (!querySnapshot.empty) {
              const userDoc = querySnapshot.docs[0];
              const data = userDoc.data();
              if (data.role !== 'admin') {
                await updateDoc(userDoc.ref, { role: 'admin' });
              }
            }
          } catch (fsError) {
            console.warn('Admin Firestore check failed (likely permissions):', fsError.message);
          }
        } else {
          // Ignore other errors during auto-init to keep console clean, 
          // or log them as warnings if they aren't critical.
          console.debug('Admin auto-init skipped or failed:', error.code);
        }
      }
    };
    initializeAdmin();
  }, []);

  const loginAnonymously = async () => {
    try {
      setLoading(true);
      await signInAnonymously(auth);
    } catch (err) {
      console.error("❌ Échec Anonyme :", err.code, err.message);
    } finally {
      setLoading(false);
    }
  };

  const loginEmail = async (email, password) => {
    try {
      setLoading(true);
      await signInWithEmailAndPassword(auth, email, password);
    } catch (err) {
      console.error("❌ Échec Email :", err.code, err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const logout = () => signOut(auth);

  return { user, userData, loading, loginAnonymously, loginEmail, logout };
}

import { useState } from 'react';

export default function Login({ onLogin, onAnonymousLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await onLogin(email, password);
    } catch {
      setError("Identifiants incorrects");
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-mictlan-black p-4">
      <div className="w-full max-w-sm bg-mictlan-dark-gray p-8 rounded-2xl border border-mictlan-gold/30 shadow-2xl">
        <div className="text-center mb-8">
          <h1 className="text-2xl font-black text-mictlan-gold tracking-[0.2em] uppercase">Mictlan Terminal</h1>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <input 
            type="email" 
            value={email} 
            onChange={(e) => setEmail(e.target.value)}
            className="w-full bg-black border border-gray-800 rounded-lg p-3 text-white outline-none focus:border-mictlan-gold"
            placeholder="Email"
          />
          <input 
            type="password" 
            value={password} 
            onChange={(e) => setPassword(e.target.value)}
            className="w-full bg-black border border-gray-800 rounded-lg p-3 text-white outline-none focus:border-mictlan-gold"
            placeholder="Mot de passe"
          />
          <button type="submit" className="w-full bg-mictlan-gold text-black font-black py-3 rounded-lg uppercase tracking-widest hover:bg-yellow-600 transition-all">
            Connexion Email
          </button>
        </form>

        <div className="relative my-6 text-center">
          <hr className="border-gray-800" />
          <span className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 bg-mictlan-dark-gray px-2 text-[10px] text-gray-500 uppercase">Ou</span>
        </div>

        <button 
          onClick={onAnonymousLogin}
          className="w-full bg-gray-800 hover:bg-gray-700 text-mictlan-gold font-bold py-3 rounded-lg text-xs uppercase tracking-widest transition-all"
        >
          Entrer en Anonyme
        </button>

        {error && <p className="text-mictlan-red text-[10px] mt-4 text-center font-bold">{error}</p>}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { db } from '../firebase/config';
import { doc, getDoc } from 'firebase/firestore';
import { Save, FileText } from 'lucide-react';
import Card from './Card'; // Assuming Card is the component name

export default function RequirementsCard() {
  const [content, setContent] = useState('');

  useEffect(() => {
    const load = async () => {
      const docRef = doc(db, 'requirements', 'current');
      const docSnap = await getDoc(docRef);
      if (docSnap.exists()) setContent(docSnap.data().text);
    };
    load();
  }, []);

  return (
    <Card title="Cahier des Charges" titleIcon={<FileText />}>
      <textarea 
        className="w-full h-48 p-4 bg-black/20 border border-gray-800 rounded-2xl font-mono text-xs text-gray-300 focus:ring-1 focus:ring-mictlan-gold/30 outline-none resize-none mb-4"
        value={content}
        onChange={(e) => setContent(e.target.value)}
      />
      <button onClick={() => alert('Sauvegardé')} className="w-full bg-gray-800 hover:bg-mictlan-gold hover:text-black text-mictlan-gold font-bold py-2 rounded-lg text-xs uppercase tracking-widest">
        <Save size={14} className="inline mr-2" /> Sauvegarder
      </button>
    </Card>
  );
}

